"use client";
import { useEffect,useMemo,useState } from "react";
import type { Player } from "../../lib/football";
import { PlayerPhoto } from "../components/PlayerPhoto";
type Tab="overview"|"players"|"separations"|"admins"|"associations"|"config"|"career"|"audit";
type PlayerSortKey="name"|"type"|"position"|"primaryRating"|"skill"|"secondaryRating"|"momentum"|"active";
type PlayerSort={key:PlayerSortKey;direction:"asc"|"desc"};
const empty={displayName:"",fullName:"",nickname:"",aliases:[],type:"monthly",primaryPosition:"Defesa",speed:3,skill:3,marking:3,goalkeeperPositioning:3,goalExit:3,active:true,notes:""};
export default function AdminApp(){const [admin,setAdmin]=useState<any>(undefined),[error,setError]=useState(""),[notice,setNotice]=useState(""),[tab,setTab]=useState<Tab>("overview"),[players,setPlayers]=useState<Player[]>([]),[seps,setSeps]=useState<any[]>([]),[admins,setAdmins]=useState<any[]>([]),[associations,setAssociations]=useState<any[]>([]),[auditData,setAuditData]=useState<any>({logs:[],actions:[],pagination:{page:1,pageSize:10,total:0,totalPages:1}}),[auditPage,setAuditPage]=useState(1),[auditPageSize,setAuditPageSize]=useState(10),[auditQuery,setAuditQuery]=useState(""),[auditAction,setAuditAction]=useState("ALL"),[auditLoading,setAuditLoading]=useState(false),[config,setConfig]=useState<any>(null),[career,setCareer]=useState<any>(null),[edit,setEdit]=useState<any>(null),[profileOpen,setProfileOpen]=useState(false),[search,setSearch]=useState(""),[playerSort,setPlayerSort]=useState<PlayerSort>({key:"name",direction:"asc"});
 const api=async(url:string,opts?:RequestInit)=>{const r=await fetch(url,opts),body=await r.text();let j:any={};if(body){try{j=JSON.parse(body)}catch{j={error:r.ok?"O servidor retornou uma resposta inválida.":`Falha no servidor (${r.status}).`}}}if(!r.ok)throw new Error(j.error||`Não foi possível concluir (${r.status}).`);return j};
 const load=async()=>{const a=await api('/api/auth');setAdmin(a.admin);if(a.admin){const [p,s,c,ad,memberData,careerData]=await Promise.all([fetch('/api/players',{cache:'no-store'}).then(r=>r.json()),api('/api/separations'),api('/api/config'),api('/api/administrators'),api('/api/member-associations'),api('/api/career/admin')]);setPlayers(p.players);setSeps(s.separations);setConfig(c.config);setAdmins(ad.administrators);setAssociations(memberData.associations||[]);setCareer(careerData)}};
 useEffect(()=>{load().catch(e=>setError(e.message))},[]);
 useEffect(()=>{if(!admin||tab!=='audit')return;const controller=new AbortController(),timer=setTimeout(()=>{setAuditLoading(true);const parameters=new URLSearchParams({page:String(auditPage),pageSize:String(auditPageSize),q:auditQuery,action:auditAction});api(`/api/audit?${parameters}`,{signal:controller.signal}).then(setAuditData).catch((error:any)=>{if(error?.name!=='AbortError')setError(error.message)}).finally(()=>{if(!controller.signal.aborted)setAuditLoading(false)})},auditQuery?300:0);return()=>{clearTimeout(timer);controller.abort()}},[admin,tab,auditPage,auditPageSize,auditQuery,auditAction]);
 if(admin===undefined)return <div className="admin-loading">Carregando painel…</div>;
 if(!admin)return <Login onLogin={load} error={error} setError={setError}/>;
 if(admin.mustChangePassword)return <FirstAccess admin={admin} onDone={load} setError={setError} error={error}/>;
 const filtered=players.filter(p=>[p.displayName,p.nickname,p.primaryPosition].some(v=>(v||'').toLowerCase().includes(search.toLowerCase()))).sort((a,b)=>comparePlayers(a,b,playerSort));
 function togglePlayerSort(key:PlayerSortKey){setPlayerSort(current=>({key,direction:current.key===key&&current.direction==='asc'?'desc':'asc'}))}
 async function savePlayer(p:any){setError("");setNotice("");try{await api('/api/players',{method:p.id?'PUT':'POST',headers:{'content-type':'application/json'},body:JSON.stringify(p)});setEdit(null);setNotice(p.id?'Jogador atualizado com sucesso.':'Jogador cadastrado com sucesso.');await load()}catch(e:any){setError(e.message)}}
 async function removeSep(id:string){if(!confirm('Excluir esta separação da visualização pública?'))return;setError("");setNotice("");await api(`/api/separations?id=${id}`,{method:'DELETE'});setNotice('Separação removida da visualização pública.');await load()}
 async function logout(){await api('/api/auth',{method:'DELETE'});setAdmin(null)}
 return <div className="admin-shell"><aside><a className="admin-brand" href="/"><b>⚽ Pelada</b><small>Pede Mais Uma</small></a><p>PAINEL ADMINISTRATIVO</p>{([['overview','Visão geral'],['players','Jogadores'],['separations','Separações'],['admins','Administradores'],['associations','Contas de jogadores'],['config','Configurações'],['career','Modo Carreira'],['audit','Auditoria']] as [Tab,string][]).map(([id,label])=><button key={id} className={tab===id?'on':''} onClick={()=>{setTab(id);setError("");setNotice("")}}>{label}</button>)}<div className="admin-user"><button type="button" className="admin-user-avatar" onClick={()=>setProfileOpen(true)} aria-label="Abrir meu perfil">{admin.email.slice(0,2).toUpperCase()}</button><div><b>{admin.email}</b><small>Administrador</small></div><button onClick={logout}>Sair</button></div></aside><main className="admin-main"><div className="admin-top"><div><small>ÁREA PROTEGIDA</small><h1>{{overview:'Visão geral',players:'Jogadores',separations:'Separações salvas',admins:'Administradores',associations:'Contas de jogadores',config:'Configurações de equilíbrio',career:'Modo Carreira',audit:'Auditoria'}[tab]}</h1></div><button type="button" className="mobile-profile" onClick={()=>setProfileOpen(true)} aria-label="Abrir meu perfil">{admin.email.slice(0,2).toUpperCase()}</button><a href="/">Ver área pública ↗</a></div>{error&&<div className="alert error">{error}</div>}{notice&&<div className="admin-notice" role="status"><span>✓</span><b>{notice}</b><button onClick={()=>setNotice("")} aria-label="Fechar mensagem">×</button></div>}
 {tab==='overview'&&<OverviewDashboard players={players} separations={seps} administrators={admins} associations={associations} config={config} career={career?.config}/>}
 {tab==='players'&&<><div className="toolbar"><input placeholder="Buscar por nome, apelido ou posição…" value={search} onChange={e=>setSearch(e.target.value)}/><button className="primary" onClick={()=>setEdit({...empty})}>+ Cadastrar jogador</button></div><PlayerTables players={filtered} sort={playerSort} onSort={togglePlayerSort} onEdit={player=>setEdit({...player,marking:player.marking??3,goalkeeperPositioning:player.goalkeeperPositioning??player.speed??3,goalExit:player.goalExit??player.marking??3})}/></>}
 {tab==='separations'&&<section className="admin-card table"><div className="tr sep th"><span>Partida</span><span>Confirmação</span><span>Jogadores</span><span>Equilíbrio</span><span></span></div>{seps.map(s=><div className="tr sep" key={s.id}><span><b>{s.matchTitle}</b><small>{s.matchDate||'Sem data'}</small></span><span>{new Date(s.confirmedAt).toLocaleString('pt-BR')}</span><span>{s.snapshot.blue.length+s.snapshot.yellow.length}</span><span className="status active">{s.balanceClassification}</span><button className="danger" onClick={()=>removeSep(s.id)}>Excluir</button></div>)}</section>}
 {tab==='admins'&&<Admins admins={admins} api={api} reload={load} setError={setError} setNotice={setNotice}/>} {tab==='associations'&&<MemberAssociations associations={associations} api={api} reload={load} setError={setError} setNotice={setNotice}/>} {tab==='config'&&config&&<ConfigForm config={config} api={api} reload={load} setError={setError} setNotice={setNotice}/>} {tab==='career'&&career&&<CareerPanel data={career} api={api} reload={load} setError={setError} setNotice={setNotice}/>} {tab==='audit'&&<AuditPanel data={auditData} loading={auditLoading} query={auditQuery} action={auditAction} pageSize={auditPageSize} onQuery={(value:string)=>{setAuditQuery(value);setAuditPage(1)}} onAction={(value:string)=>{setAuditAction(value);setAuditPage(1)}} onPageSize={(value:number)=>{setAuditPageSize(value);setAuditPage(1)}} onPage={setAuditPage}/>}
 </main>{edit&&<PlayerForm player={edit} onClose={()=>setEdit(null)} onSave={savePlayer}/>} {profileOpen&&<ProfileModal admin={admin} api={api} onClose={()=>setProfileOpen(false)} onChanged={(message:string)=>{setProfileOpen(false);setNotice(message);load().catch(e=>setError(e.message))}}/>}</div>}
function OverviewDashboard({players,separations,administrators,associations,config,career}:any){
 const activePlayers=players.filter((player:Player)=>player.active),guests=players.filter((player:Player)=>player.type==='guest'),memberAccounts=associations.filter((association:any)=>association.accountType==='member'),activeMemberAccounts=memberAccounts.filter((association:any)=>association.active),careerEnabled=Boolean(career?.enabled);
 const percentage=(value:number|undefined,fallback:number)=>`${Math.round(Number(value??fallback)*100)}%`;
 return <><div className="stat-grid overview-primary-grid"><Stat label="Jogadores ativos" value={activePlayers.length} note={`${guests.length} convidados`}/><Stat label="Separações salvas" value={separations.length} note="Histórico confirmado"/><Stat label="Administradores" value={administrators.filter((item:any)=>item.active).length} note={`${administrators.length} cadastrados`}/><Stat label="Contas de jogadores" value={memberAccounts.length} note={`${activeMemberAccounts.length} ativas`}/></div><div className="overview-system-grid"><section className="admin-card overview-system-card"><div className="overview-card-head"><div><small>ALGORITMO</small><h2>Pesos de equilíbrio</h2></div><span>Total 100%</span></div><div className="overview-metric-grid weights"><OverviewMetric label="Velocidade" value={percentage(config?.speedWeight,.48)} note="Influência no overall"/><OverviewMetric label="Habilidade" value={percentage(config?.skillWeight,.32)} note="Influência técnica"/><OverviewMetric label="Marcação" value={percentage(config?.markingWeight,.2)} note="Critério defensivo"/></div></section><section className="admin-card overview-system-card career-overview"><div className="overview-card-head"><div><small>MODO CARREIRA</small><h2>Estado das funcionalidades</h2></div><StatusBadge active={careerEnabled}/></div><div className="overview-metric-grid career-states"><OverviewStatus label="Gols e assistências" active={careerEnabled&&Boolean(career?.trackContributions)} masterEnabled={careerEnabled}/><OverviewStatus label="Cards por nível" active={careerEnabled&&Boolean(career?.cardTiersEnabled)} masterEnabled={careerEnabled}/><OverviewMetric label="Multiplicador do momentum" value={Number(career?.momentumMultiplier??1).toFixed(1)} note="Influência atual no overall"/></div></section></div><section className="admin-card overview-activity"><h2>Atividade recente</h2>{separations.length===0?<p className="overview-empty-activity">Nenhuma separação confirmada ainda.</p>:separations.slice(0,5).map((separation:any)=><div className="activity" key={separation.id}><span>⚽</span><div><b>{separation.matchTitle}</b><small>{new Date(separation.confirmedAt).toLocaleString('pt-BR')}</small></div><em>{separation.balanceClassification}</em></div>)}</section></>
}
function OverviewMetric({label,value,note}:{label:string;value:string;note:string}){return <article className="overview-metric"><small>{label}</small><b>{value}</b><span>{note}</span></article>}
function OverviewStatus({label,active,masterEnabled}:{label:string;active:boolean;masterEnabled:boolean}){return <article className="overview-metric overview-status"><small>{label}</small><StatusBadge active={active}/><span>{masterEnabled?(active?'Disponível no sistema':'Desativado na configuração'):'Modo Carreira desativado'}</span></article>}
function StatusBadge({active}:{active:boolean}){return <strong className={active?'overview-status-badge active':'overview-status-badge'}><i></i>{active?'Ativo':'Inativo'}</strong>}
function Login({onLogin,error,setError}:any){
 const [mode,setMode]=useState<'login'|'request'|'reset'>('login'),[email,setEmail]=useState('admin'),[password,setPassword]=useState('admin'),[confirmation,setConfirmation]=useState(''),[resetToken,setResetToken]=useState(''),[message,setMessage]=useState(''),[busy,setBusy]=useState(false);
 useEffect(()=>{const token=new URLSearchParams(window.location.search).get('reset');if(token){setResetToken(token);setPassword('');setMode('reset')}},[]);
 async function submit(e:any){e.preventDefault();setError('');setBusy(true);try{const r=await fetch('/api/auth',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({email,password})});const j=await r.json();if(!r.ok)setError(j.error);else await onLogin()}catch{setError('Não foi possível conectar ao servidor.')}finally{setBusy(false)}}
 async function requestReset(e:any){e.preventDefault();setError('');setMessage('');setBusy(true);try{const r=await fetch('/api/password-reset',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({email})});const j=await r.json();if(!r.ok)setError(j.error);else setMessage(j.message)}catch{setError('Não foi possível solicitar a recuperação agora.')}finally{setBusy(false)}}
 async function resetPassword(e:any){e.preventDefault();setError('');setMessage('');if(password!==confirmation){setError('As senhas informadas não coincidem.');return}setBusy(true);try{const r=await fetch('/api/password-reset',{method:'PUT',headers:{'content-type':'application/json'},body:JSON.stringify({token:resetToken,password})});const j=await r.json();if(!r.ok)setError(j.error);else{window.history.replaceState({},'',window.location.pathname);setMessage(j.message);setPassword('');setConfirmation('');setMode('login')}}catch{setError('Não foi possível redefinir a senha agora.')}finally{setBusy(false)}}
 const copy=<div className="login-copy"><a href="/">⚽ <b>Pelada Pede Mais Uma</b></a><div><span>ÁREA DO ORGANIZADOR</span><h1>O controle da pelada,<br/>do seu jeito.</h1><p>Gerencie jogadores, ajuste critérios de equilíbrio e cuide do histórico com segurança.</p></div><small>Times equilibrados. Resenha garantida.</small></div>;
 if(mode==='request')return <div className="login-page">{copy}<form className="login-card" onSubmit={requestReset}><div className="ball">✉️</div><h2>Recuperar senha</h2><p>Enviaremos um link de uso único para o e-mail do administrador.</p>{error&&<div className="alert error">{error}</div>}{message&&<div className="admin-notice" role="status"><span>✓</span><b>{message}</b></div>}<label>E-mail cadastrado<input type="email" value={email==='admin'?'':email} onChange={e=>setEmail(e.target.value)} autoComplete="email" required/></label><button className="primary" disabled={busy}>{busy?'Enviando…':'Enviar link de recuperação'}</button><button className="forgot login-back" type="button" onClick={()=>{setMode('login');setError('');setMessage('')}}>← Voltar ao login</button></form></div>;
 if(mode==='reset')return <div className="login-page">{copy}<form className="login-card" onSubmit={resetPassword}><div className="ball">🔐</div><h2>Criar nova senha</h2><p>O link pode ser utilizado uma única vez e expira em 30 minutos.</p>{error&&<div className="alert error">{error}</div>}<label>Nova senha<input type="password" minLength={8} value={password} onChange={e=>setPassword(e.target.value)} autoComplete="new-password" required/><small>Mínimo de 8 caracteres; não pode ser “admin”.</small></label><label>Confirmar nova senha<input type="password" minLength={8} value={confirmation} onChange={e=>setConfirmation(e.target.value)} autoComplete="new-password" required/></label><button className="primary" disabled={busy}>{busy?'Salvando…':'Redefinir senha'}</button><button className="forgot login-back" type="button" onClick={()=>{window.history.replaceState({},'',window.location.pathname);setMode('login');setError('')}}>Cancelar</button></form></div>;
 return <div className="login-page">{copy}<form className="login-card" onSubmit={submit}><div className="ball">⚽</div><h2>Bem-vindo de volta</h2><p>Entre para acessar o painel administrativo.</p>{error&&<div className="alert error">{error}</div>}{message&&<div className="admin-notice" role="status"><span>✓</span><b>{message}</b></div>}<label>Usuário ou e-mail<input value={email} onChange={e=>setEmail(e.target.value)} autoComplete="username"/></label><label>Senha<input type="password" value={password} onChange={e=>setPassword(e.target.value)} autoComplete="current-password"/></label><button className="forgot" type="button" onClick={()=>{setEmail(email==='admin'?'':email);setMode('request');setError('');setMessage('')}}>Esqueci minha senha</button><button className="primary" disabled={busy}>{busy?'Entrando…':'Entrar no painel →'}</button><a href="/">← Voltar para a área pública</a></form></div>
}
function FirstAccess({admin,onDone,setError,error}:any){const [email,setEmail]=useState(admin.email==='admin'?'':admin.email),[password,setPassword]=useState('');async function go(e:any){e.preventDefault();const r=await fetch('/api/auth',{method:'PUT',headers:{'content-type':'application/json'},body:JSON.stringify({email,password})});const j=await r.json();if(!r.ok)setError(j.error);else onDone()}return <div className="login-page single"><form className="login-card" onSubmit={go}><div className="ball">🔐</div><h2>Proteja sua conta</h2><p>No primeiro acesso, informe seu e-mail e troque a senha padrão.</p>{error&&<div className="alert error">{error}</div>}<label>E-mail<input type="email" value={email} onChange={e=>setEmail(e.target.value)} required/></label><label>Nova senha<input type="password" minLength={8} value={password} onChange={e=>setPassword(e.target.value)} required/><small>Mínimo de 8 caracteres; não pode ser “admin”.</small></label><button className="primary">Salvar e continuar</button></form></div>}
function ProfileModal({admin,api,onClose,onChanged}:any){
 const [currentPassword,setCurrentPassword]=useState(''),[newPassword,setNewPassword]=useState(''),[confirmation,setConfirmation]=useState(''),[error,setError]=useState(''),[saving,setSaving]=useState(false);
 async function save(e:any){e.preventDefault();setError('');if(newPassword!==confirmation){setError('A confirmação não corresponde à nova senha.');return}setSaving(true);try{const response=await api('/api/profile/password',{method:'PUT',headers:{'content-type':'application/json'},body:JSON.stringify({currentPassword,newPassword,confirmation})});onChanged(response.message)}catch(e:any){setError(e.message)}finally{setSaving(false)}}
 return <div className="modal-back"><section className="profile-modal" role="dialog" aria-modal="true" aria-labelledby="profile-title"><button className="close" type="button" onClick={onClose} aria-label="Fechar perfil">×</button><div className="profile-heading"><span>{admin.email.slice(0,2).toUpperCase()}</span><div><small>MINHA CONTA</small><h2 id="profile-title">Perfil do administrador</h2></div></div><div className="profile-info"><span><small>E-mail</small><b>{admin.email}</b></span><span><small>Cadastrado em</small><b>{admin.createdAt?new Date(admin.createdAt).toLocaleDateString('pt-BR'):'Não informado'}</b></span></div><form className="profile-password" onSubmit={save}><h3>Alterar senha</h3><p>Confirme sua senha atual e escolha uma nova senha com pelo menos 8 caracteres.</p>{error&&<div className="alert error" role="alert">{error}</div>}<label>Senha atual<input type="password" value={currentPassword} onChange={e=>setCurrentPassword(e.target.value)} autoComplete="current-password" required/></label><label>Nova senha<input type="password" minLength={8} value={newPassword} onChange={e=>setNewPassword(e.target.value)} autoComplete="new-password" required/><small>Mínimo de 8 caracteres.</small></label><label>Confirmar nova senha<input type="password" minLength={8} value={confirmation} onChange={e=>setConfirmation(e.target.value)} autoComplete="new-password" required/></label><div className="editor-actions"><button type="button" className="ghost" onClick={onClose}>Cancelar</button><button className="primary" disabled={saving}>{saving?'Alterando…':'Alterar senha'}</button></div></form></section></div>
}
function LegacyPlayerForm({player,onClose,onSave}:any){
 const [p,setP]=useState({...player,marking:player.marking??3,goalkeeperPositioning:player.goalkeeperPositioning??player.speed??3,goalExit:player.goalExit??player.marking??3}),[uploading,setUploading]=useState(false),[uploadError,setUploadError]=useState("");
 const set=(k:string,v:any)=>setP((x:any)=>({...x,[k]:v}));
 const goalkeeper=p.type==='goalkeeper'||p.primaryPosition==='Goleiro';
 async function upload(file?:File){if(!file)return;setUploading(true);setUploadError("");try{const response=await fetch("/api/upload",{method:"POST",headers:{"content-type":file.type||"application/octet-stream","x-file-name":encodeURIComponent(file.name)},body:file});const payload=await response.json().catch(()=>({error:"O servidor não retornou uma resposta válida."}));if(!response.ok)throw new Error(payload.error||"Não foi possível enviar a foto.");set("photoUrl",payload.url)}catch(error:any){setUploadError(error.message==='Failed to fetch'?"Não foi possível conectar ao serviço de fotos. Verifique se o servidor local está em execução.":error.message)}finally{setUploading(false)}}
 return <div className="modal-back"><form className="editor" onSubmit={e=>{e.preventDefault();onSave(p)}}><button className="close" type="button" onClick={onClose}>×</button><h2>{p.id?'Editar jogador':'Cadastrar jogador'}</h2><div className="photo-editor"><AdminAvatar player={p}/><div><label className="photo-upload">{uploading?"Enviando…":"Selecionar foto"}<input type="file" accept="image/jpeg,image/png,image/webp" disabled={uploading} onChange={e=>upload(e.target.files?.[0])}/></label>{p.photoUrl&&<button type="button" onClick={()=>set("photoUrl",null)}>Remover foto</button>}<small>JPG, PNG ou WebP de até 5 MB.</small>{uploadError&&<em>{uploadError}</em>}</div></div><div className="form-grid"><label>Nome para exibição<input value={p.displayName} onChange={e=>set('displayName',e.target.value)} required/></label><label>Nome completo<input value={p.fullName} onChange={e=>set('fullName',e.target.value)} required/></label><label>Apelido<input value={p.nickname||''} onChange={e=>set('nickname',e.target.value)}/></label><label>Tipo<select value={p.type} onChange={e=>set('type',e.target.value)}><option value="monthly">Mensalista</option><option value="guest">Convidado</option><option value="goalkeeper">Goleiro</option></select></label><label>Posição<select value={p.primaryPosition} onChange={e=>set('primaryPosition',e.target.value)}><option>Defesa</option><option>Meio-campo</option><option>Ataque</option><option>Goleiro</option></select></label><RatingSlider label="Velocidade" value={p.speed} onChange={value=>set("speed",value)}/><RatingSlider label="Habilidade" value={p.skill} onChange={value=>set("skill",value)}/><RatingSlider label="Marcação" value={p.marking} onChange={value=>set("marking",value)}/><label className="check"><input type="checkbox" checked={p.active} onChange={e=>set('active',e.target.checked)}/> Jogador ativo</label><label className="wide">Nomes alternativos<input value={(p.aliases||[]).join(', ')} onChange={e=>set('aliases',e.target.value.split(',').map(x=>x.trim()).filter(Boolean))}/></label><label className="wide">Observações<textarea value={p.notes||''} onChange={e=>set('notes',e.target.value)}/></label></div><div className="editor-actions"><button type="button" className="ghost" onClick={onClose}>Cancelar</button><button className="primary" disabled={uploading}>Salvar jogador</button></div></form></div>
}
function PlayerForm({player,onClose,onSave}:any){
 const [p,setP]=useState({...player,marking:player.marking??3,goalkeeperPositioning:player.goalkeeperPositioning??player.speed??3,goalExit:player.goalExit??player.marking??3}),[uploading,setUploading]=useState(false),[uploadError,setUploadError]=useState("");
 const set=(key:string,value:any)=>setP((current:any)=>({...current,[key]:value}));
 const goalkeeper=p.type==='goalkeeper'||p.primaryPosition==='Goleiro';
 async function upload(file?:File){if(!file)return;setUploading(true);setUploadError("");try{const response=await fetch("/api/upload",{method:"POST",headers:{"content-type":file.type||"application/octet-stream","x-file-name":encodeURIComponent(file.name)},body:file});const payload=await response.json().catch(()=>({error:"O servidor não retornou uma resposta válida."}));if(!response.ok)throw new Error(payload.error||"Não foi possível enviar a foto.");set("photoUrl",payload.url)}catch(error:any){setUploadError(error.message)}finally{setUploading(false)}}
 function changeType(type:string){setP((current:any)=>({...current,type,primaryPosition:type==='goalkeeper'?'Goleiro':current.primaryPosition==='Goleiro'?'Defesa':current.primaryPosition}))}
 function changePosition(primaryPosition:string){setP((current:any)=>({...current,primaryPosition,type:primaryPosition==='Goleiro'?'goalkeeper':current.type==='goalkeeper'?'monthly':current.type}))}
 return <div className="modal-back"><form className="editor" onSubmit={event=>{event.preventDefault();onSave(p)}}><button className="close" type="button" onClick={onClose}>×</button><h2>{p.id?'Editar jogador':'Cadastrar jogador'}</h2><div className="photo-editor"><AdminAvatar player={p}/><div><label className="photo-upload">{uploading?'Enviando…':'Selecionar foto'}<input type="file" accept="image/jpeg,image/png,image/webp" disabled={uploading} onChange={event=>upload(event.target.files?.[0])}/></label>{p.photoUrl&&<button type="button" onClick={()=>set('photoUrl',null)}>Remover foto</button>}<small>JPG, PNG ou WebP de até 5 MB.</small>{uploadError&&<em>{uploadError}</em>}</div></div><div className="form-grid"><label>Nome para exibição<input value={p.displayName} onChange={event=>set('displayName',event.target.value)} required/></label><label>Nome completo<input value={p.fullName} onChange={event=>set('fullName',event.target.value)} required/></label><label>Apelido<input value={p.nickname||''} onChange={event=>set('nickname',event.target.value)}/></label><label>Tipo<select value={p.type} onChange={event=>changeType(event.target.value)}><option value="monthly">Mensalista</option><option value="guest">Convidado</option><option value="goalkeeper">Goleiro</option></select></label><label>Posição<select value={p.primaryPosition} onChange={event=>changePosition(event.target.value)}><option>Defesa</option><option>Meio-campo</option><option>Ataque</option><option>Goleiro</option></select></label>{goalkeeper?<><RatingSlider label="Habilidade (reflexos e agilidade)" value={p.skill} onChange={value=>set('skill',value)}/><RatingSlider label="Posicionamento" value={p.goalkeeperPositioning} onChange={value=>set('goalkeeperPositioning',value)}/><RatingSlider label="Saída de gol (coragem)" value={p.goalExit} onChange={value=>set('goalExit',value)}/></>:<><RatingSlider label="Velocidade" value={p.speed} onChange={value=>set('speed',value)}/><RatingSlider label="Habilidade" value={p.skill} onChange={value=>set('skill',value)}/><RatingSlider label="Marcação" value={p.marking} onChange={value=>set('marking',value)}/></>}<label className="check"><input type="checkbox" checked={p.active} onChange={event=>set('active',event.target.checked)}/> Jogador ativo</label><label className="wide">Nomes alternativos<input value={(p.aliases||[]).join(', ')} onChange={event=>set('aliases',event.target.value.split(',').map((name:string)=>name.trim()).filter(Boolean))}/></label><label className="wide">Observações<textarea value={p.notes||''} onChange={event=>set('notes',event.target.value)}/></label></div><div className="editor-actions"><button type="button" className="ghost" onClick={onClose}>Cancelar</button><button className="primary" disabled={uploading}>Salvar jogador</button></div></form></div>
}
function Admins({admins,api,reload,setError,setNotice}:any){const [email,setEmail]=useState(''),[password,setPassword]=useState('');async function add(e:any){e.preventDefault();setError("");setNotice("");try{await api('/api/administrators',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({email,password})});setEmail('');setPassword('');setNotice('Administrador cadastrado com sucesso.');await reload()}catch(e:any){setError(e.message)}}async function toggle(a:any){setError("");setNotice("");try{await api('/api/administrators',{method:'PUT',headers:{'content-type':'application/json'},body:JSON.stringify({id:a.id,active:!a.active})});setNotice(a.active?'Administrador desativado com sucesso.':'Administrador ativado com sucesso.');await reload()}catch(e:any){setError(e.message)}}return <><form className="inline-form" onSubmit={add}><input type="email" placeholder="novo@administrador.com" value={email} onChange={e=>setEmail(e.target.value)} required/><input type="password" minLength={8} placeholder="Senha inicial (8+ caracteres)" value={password} onChange={e=>setPassword(e.target.value)} required/><button className="primary">Cadastrar administrador</button></form><section className="admin-card table"><div className="tr admin-tr th"><span>E-mail</span><span>Cadastro</span><span>Atualização</span><span>Status</span><span></span></div>{admins.map((a:any)=><div className="tr admin-tr" key={a.id}><span><b>{a.email}</b></span><span>{new Date(a.createdAt).toLocaleDateString('pt-BR')}</span><span>{new Date(a.updatedAt).toLocaleDateString('pt-BR')}</span><span className={a.active?'status active':'status'}>{a.active?'Ativo':'Inativo'}</span><button className="ghost" onClick={()=>toggle(a)}>{a.active?'Desativar':'Ativar'}</button></div>)}</section></>}
function MemberAssociations({associations,api,reload,setError,setNotice}:any){
 async function remove(account:any){if(!account.playerId||!confirm(`Desassociar o login ${account.email} do jogador ${account.playerName}? O usuário poderá selecionar outro jogador no próximo acesso.`))return;setError("");setNotice("");try{const result=await api(`/api/member-associations?id=${encodeURIComponent(account.id)}&type=${encodeURIComponent(account.accountType)}`,{method:'DELETE'});setNotice(result.message);await reload()}catch(error:any){setError(error.message)}}
 return <section className="member-associations"><div className="admin-card association-summary"><div><b>{associations.length}</b><span>contas cadastradas</span></div><div><b>{associations.filter((item:any)=>item.playerId).length}</b><span>jogadores associados</span></div><p>Contas comuns e administradores podem ter um jogador. Cada jogador aceita somente um login, independentemente do tipo da conta.</p></div><div className="admin-card table"><div className="tr member-association-tr th"><span>Login</span><span>Jogador associado</span><span>Tipo / posição</span><span>Cadastro</span><span>Último acesso</span><span></span></div>{associations.length?associations.map((item:any)=><div className="tr member-association-tr" key={`${item.accountType}-${item.id}`}><span><b>{item.email}</b><small>{item.accountType==='administrator'?'Administrador':item.active?'Conta de jogador ativa':'Conta de jogador inativa'}</small></span><span>{item.playerName?<b>{item.playerName}</b>:<em>Sem associação</em>}</span><span>{item.playerName?`${item.playerType==='guest'?'Convidado':item.playerType==='goalkeeper'?'Goleiro':'Mensalista'} · ${item.primaryPosition}`:'—'}</span><span>{new Date(item.createdAt).toLocaleDateString('pt-BR')}</span><span>{item.lastLoginAt?new Date(item.lastLoginAt).toLocaleString('pt-BR'):'Nunca acessou'}</span>{item.playerId?<button className="danger" onClick={()=>remove(item)}>Desassociar</button>:<span className="status">Aguardando jogador</span>}</div>):<div className="player-table-empty">Nenhuma conta cadastrada.</div>}</div></section>
}
function HelpTip({id,text}:{id:string,text:string}){
 return <span className="help-tip"><button type="button" aria-label="Ver explicação" aria-describedby={id}>?</button><span id={id} role="tooltip">{text}</span></span>
}
function ConfigForm({config,api,reload,setError,setNotice}:any){
 const [c,setC]=useState(config),[saving,setSaving]=useState(false);
 const set=(k:string,v:any)=>setC((x:any)=>({...x,[k]:v}));
 const roundWeight=(value:number)=>Math.round(value*100)/100;
 const weightKeys=['speedWeight','skillWeight','markingWeight'] as const;
 function setWeight(key:typeof weightKeys[number],value:number){
  setC((current:any)=>{
   const selected=roundWeight(value),remaining=roundWeight(1-selected),others=weightKeys.filter(item=>item!==key);
   const otherTotal=Number(current[others[0]]||0)+Number(current[others[1]]||0);
   const first=otherTotal>0?roundWeight(remaining*Number(current[others[0]]||0)/otherTotal):roundWeight(remaining/2);
   return {...current,[key]:selected,[others[0]]:first,[others[1]]:roundWeight(remaining-first)};
  });
 }
 async function save(e:any){e.preventDefault();setError("");setNotice("");setSaving(true);try{const response=await api('/api/config',{method:'PUT',headers:{'content-type':'application/json'},body:JSON.stringify(c)});setNotice(response.message||'Configurações salvas com sucesso.');await reload()}catch(e:any){setError(e.message)}finally{setSaving(false)}}
 return <form className="admin-card settings" onSubmit={save}><div><h2>Pesos do algoritmo</h2><p>Os três critérios sempre somam 100%. Ao alterar um peso, os outros dois são ajustados proporcionalmente.</p><div className="weight-total"><span>Total configurado <HelpTip id="help-total" text="Confirma que a soma dos pesos de velocidade, habilidade e marcação está em 100%. O sistema mantém esse total automaticamente."/></span><b>{Math.round((c.speedWeight+c.skillWeight+c.markingWeight)*100)}%</b></div><div className="setting-field"><div className="setting-label"><label htmlFor="speed-weight">Peso da velocidade</label><HelpTip id="help-speed" text="Define quanto a nota de velocidade de cada jogador influencia o cálculo de equilíbrio. Quanto maior o percentual, mais o algoritmo evita concentrar jogadores rápidos no mesmo time."/><b>{Math.round(c.speedWeight*100)}%</b></div><input id="speed-weight" type="range" min="0" max="1" step=".01" value={c.speedWeight} onChange={e=>setWeight('speedWeight',+e.target.value)}/></div><div className="setting-field"><div className="setting-label"><label htmlFor="skill-weight">Peso da habilidade</label><HelpTip id="help-skill" text="Define quanto a nota de habilidade técnica influencia o equilíbrio. Um peso maior dá mais importância à distribuição dos jogadores mais habilidosos."/><b>{Math.round(c.skillWeight*100)}%</b></div><input id="skill-weight" type="range" min="0" max="1" step=".01" value={c.skillWeight} onChange={e=>setWeight('skillWeight',+e.target.value)}/></div><div className="setting-field"><div className="setting-label"><label htmlFor="marking-weight">Peso da marcação</label><HelpTip id="help-marking" text="Define quanto a capacidade de marcação e contribuição defensiva influencia o equilíbrio. Aumente para distribuir melhor os bons marcadores entre os times."/><b>{Math.round(c.markingWeight*100)}%</b></div><input id="marking-weight" type="range" min="0" max="1" step=".01" value={c.markingWeight} onChange={e=>setWeight('markingWeight',+e.target.value)}/></div></div><div><h2>Limites e tentativas</h2><div className="setting-field"><div className="setting-label"><label htmlFor="default-player-count">Quantidade padrão</label><HelpTip id="help-player-count" text="Quantidade de jogadores sugerida inicialmente na área pública. Esse valor apenas preenche o campo por padrão e pode ser alterado ao montar cada pelada."/></div><input id="default-player-count" type="number" min="2" value={c.defaultPlayerCount} onChange={e=>set('defaultPlayerCount',+e.target.value)}/></div><div className="setting-field"><div className="setting-label"><label htmlFor="position-difference">Diferença máxima por posição</label><HelpTip id="help-position-difference" text="Limita a diferença de jogadores da mesma posição entre os dois times. Valor 0 exige quantidades iguais quando possível; valor 1 permite um jogador de diferença."/></div><input id="position-difference" type="number" min="0" max="3" value={c.maximumPositionDifference} onChange={e=>set('maximumPositionDifference',+e.target.value)}/></div><div className="setting-field"><div className="setting-label"><label htmlFor="protected-players">Melhores protegidos (%)</label><HelpTip id="help-protected" text="Percentual dos jogadores com maior pontuação que o algoritmo procura distribuir primeiro entre os times, reduzindo a chance de os melhores ficarem juntos."/></div><input id="protected-players" type="number" min="0" max="100" value={c.protectedTopPlayersPercentage*100} onChange={e=>set('protectedTopPlayersPercentage',+e.target.value/100)}/></div><div className="setting-field"><div className="setting-label"><label htmlFor="algorithm-attempts">Tentativas do algoritmo</label><HelpTip id="help-attempts" text="Número de combinações de times avaliadas antes de escolher o melhor resultado. Mais tentativas podem encontrar uma separação melhor, mas aumentam o tempo de processamento."/></div><input id="algorithm-attempts" type="number" min="300" max="10000" value={c.algorithmAttempts} onChange={e=>set('algorithmAttempts',+e.target.value)}/></div></div><div className="settings-actions"><button type="button" className="ghost" onClick={()=>setC({...config,speedWeight:.48,skillWeight:.32,markingWeight:.2,maximumPositionDifference:1,protectedTopPlayersPercentage:.25,defaultPlayerCount:22})}>Restaurar padrões</button><button className="primary" disabled={saving}>{saving?'Salvando…':'Salvar configurações'}</button></div></form>
}
function CareerPanel({data,api,reload,setError,setNotice}:any){
 const [c,setC]=useState({...data.config}),[saving,setSaving]=useState(false),[open,setOpen]=useState<string|null>(null);
 useEffect(()=>setC({...data.config}),[data.config]);
 const set=(key:string,value:any)=>setC((current:any)=>({...current,[key]:value}));
 async function save(event:any){event.preventDefault();setSaving(true);setError("");setNotice("");try{const response=await api('/api/career/admin',{method:'PUT',headers:{'content-type':'application/json'},body:JSON.stringify(c)});setNotice(response.message);await reload()}catch(error:any){setError(error.message)}finally{setSaving(false)}}
 async function closeMatch(id:string){if(!confirm('Encerrar esta votação agora? O resultado e o momentum serão finais e os votos não poderão mais ser alterados.'))return;try{const response=await api('/api/career/admin',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({matchId:id})});setNotice(response.message);await reload()}catch(error:any){setError(error.message)}}
 async function removeVote(id:string){if(!confirm('Remover este voto? O jogador poderá votar novamente enquanto a votação estiver aberta.'))return;try{const response=await api(`/api/career/admin?voteId=${encodeURIComponent(id)}`,{method:'DELETE'});setNotice(response.message);await reload()}catch(error:any){setError(error.message)}}
 return <div className="career-admin"><form className="admin-card career-config" onSubmit={save}><div className="career-config-head"><div><h2>Configurações do Modo Carreira</h2><p>O momentum é multiplicado pelo peso configurado antes de alterar o overall, que permanece entre 1 e 5 com uma casa decimal.</p></div><div className="career-switches"><label className="career-switch"><input type="checkbox" checked={c.enabled} onChange={e=>set('enabled',e.target.checked)}/><span>{c.enabled?'Ativado':'Desativado'}</span></label><label className="career-switch contribution-switch"><input type="checkbox" checked={c.trackContributions} onChange={e=>set('trackContributions',e.target.checked)}/><span>Gols e assistências</span></label><label className="career-switch tier-switch"><input type="checkbox" checked={Boolean(c.cardTiersEnabled)} onChange={e=>set('cardTiersEnabled',e.target.checked)}/><span>Cards por nível</span></label></div></div><div className="career-config-grid"><CareerNumber label="Multiplicador do momentum" value={c.momentumMultiplier} onChange={(v:number)=>set('momentumMultiplier',v)} min={0} max={5}/><CareerNumber label="Bônus da equipe vencedora" value={c.winnerBonus} onChange={(v:number)=>set('winnerBonus',v)} min={0} max={1}/><CareerNumber label="Ônus da equipe perdedora" value={c.loserPenalty} onChange={(v:number)=>set('loserPenalty',v)} min={-1} max={0}/><CareerNumber label="Votação aberta por (dias)" value={c.votingDays} onChange={(v:number)=>set('votingDays',v)} min={1} max={30} step={1}/></div><CardTierThresholds config={c} set={set}/><div className="career-prizes"><section><h3>Man of the Match</h3><CareerNumber label="3º lugar" value={c.motmThird} onChange={(v:number)=>set('motmThird',v)} min={0} max={1}/><CareerNumber label="2º lugar" value={c.motmSecond} onChange={(v:number)=>set('motmSecond',v)} min={0} max={1}/><CareerNumber label="1º lugar" value={c.motmFirst} onChange={(v:number)=>set('motmFirst',v)} min={0} max={1}/></section><section><h3>Deception of the Match</h3><CareerNumber label="3º lugar" value={c.dotmThird} onChange={(v:number)=>set('dotmThird',v)} min={-1} max={0}/><CareerNumber label="2º lugar" value={c.dotmSecond} onChange={(v:number)=>set('dotmSecond',v)} min={-1} max={0}/><CareerNumber label="1º lugar" value={c.dotmFirst} onChange={(v:number)=>set('dotmFirst',v)} min={-1} max={0}/></section></div><div className="settings-actions"><button className="primary" disabled={saving}>{saving?'Salvando…':'Salvar Modo Carreira'}</button></div></form><section className="career-match-list"><div className="section-head"><div><h2>Votações por seleção</h2><p>Votos podem ser removidos somente enquanto a votação estiver aberta.</p></div></div>{data.matches.length===0?<div className="admin-card empty-admin"><b>Nenhuma partida confirmada</b><p>Registre o placar em uma separação salva para abrir a votação.</p></div>:data.matches.map((match:any)=><article className="admin-card career-match-admin" key={match.id}><button className="career-match-summary" onClick={()=>setOpen(open===match.id?null:match.id)}><div><small>{match.status==='OPEN'?'VOTAÇÃO ABERTA':'VOTAÇÃO ENCERRADA'}</small><h3>{match.matchTitle}</h3><span>{match.matchDate||'Sem data'} · encerra em {new Date(match.closesAt).toLocaleString('pt-BR')}</span></div><strong>{match.blueScore} × {match.yellowScore}</strong><em>{match.votes.length} votos</em><i>{open===match.id?'−':'+'}</i></button>{open===match.id&&<div className="career-match-body">{match.votes.length===0?<p className="empty">Nenhum voto recebido.</p>:match.votes.map((vote:any)=><div className="career-vote-row" key={vote.id}><div><b>{vote.voterName}</b><small>{new Date(vote.createdAt).toLocaleString('pt-BR')}</small></div><span><b>Melhores:</b> {vote.motm.map((entry:any,index:number)=>`${index+1}º ${entry.name}`).join(', ')}</span><span><b>Piores:</b> {vote.dotm.map((entry:any,index:number)=>`${index+1}º ${entry.name}`).join(', ')}</span>{match.status==='OPEN'&&<button className="danger" onClick={()=>removeVote(vote.id)}>Remover</button>}</div>)}{match.status==='OPEN'?<button className="danger career-close" onClick={()=>closeMatch(match.id)}>Encerrar votação antecipadamente</button>:<p className="career-final-note">Resultado final aplicado em {new Date(match.closedAt).toLocaleString('pt-BR')}. Os votos estão bloqueados.</p>}</div>}</article>)}</section></div>
}
function CardTierThresholds({config,set}:{config:any;set:(key:string,value:any)=>void}){
 const legendaryStart=Math.min(5,Math.round((Number(config.cardGoldMax??4.5)+.1)*10)/10);
 return <section className={`card-tier-settings ${config.cardTiersEnabled?'enabled':'disabled'}`}><div className="card-tier-settings-head"><div><h3>Níveis dos cards</h3><p>Defina a nota máxima de cada faixa. O próximo nível começa automaticamente 0,1 ponto acima.</p></div><span>{config.cardTiersEnabled?'Aplicado nos cards e na lista pública':'Pré-configurado, mas desativado'}</span></div><div className="card-tier-grid"><div className="card-tier-option bronze"><CareerNumber label="Bronze até" value={config.cardBronzeMax??2.4} onChange={(value:number)=>set('cardBronzeMax',value)} min={1} max={4.7}/></div><div className="card-tier-option silver"><CareerNumber label="Prata até" value={config.cardSilverMax??3.9} onChange={(value:number)=>set('cardSilverMax',value)} min={1.1} max={4.8}/></div><div className="card-tier-option gold"><CareerNumber label="Ouro até" value={config.cardGoldMax??4.5} onChange={(value:number)=>set('cardGoldMax',value)} min={1.2} max={4.9}/></div><div className="card-tier-option legendary"><small>Lendário</small><b>Acima de {Number(config.cardGoldMax??4.5).toFixed(1)}</b><span>A partir de {legendaryStart.toFixed(1)}</span></div></div><p className="card-tier-order">Os limites precisam estar em ordem: Bronze &lt; Prata &lt; Ouro. Todos aceitam uma casa decimal.</p></section>
}
function CareerNumber({label,value,onChange,min,max,step=.1}:any){
 const negative=Number(value)<0;
 const descriptions:Record<string,string>={
  'Multiplicador do momentum':'Controla quanto do momentum acumulado influencia o overall. O cálculo usa momentum × multiplicador: 0 ignora o momentum, 1 aplica o valor integral e valores maiores ampliam seu efeito positivo ou negativo.',
  'Bônus da equipe vencedora':'Valor acrescentado ao momentum de cada jogador do time vencedor assim que o administrador confirma o placar. Em caso de empate, nenhuma equipe recebe esse bônus.',
  'Ônus da equipe perdedora':'Valor descontado do momentum de cada jogador do time perdedor quando o placar é confirmado. Use um número negativo; empates não aplicam este ônus.',
  'Votação aberta por (dias)':'Quantidade de dias em que os participantes poderão votar depois da confirmação do placar. Ao vencer o prazo, a votação é encerrada e os resultados são aplicados automaticamente.',
  'Bronze até':'Maior overall que ainda usa o card bronze. O nível prata começa 0,1 ponto acima deste valor.',
  'Prata até':'Maior overall que ainda usa o card prata. O nível ouro começa 0,1 ponto acima deste valor.',
  'Ouro até':'Maior overall que ainda usa o card ouro. Jogadores acima deste valor recebem o card lendário.',
 };
 const podiumDescriptions:Record<string,string>={
  '3º lugar':negative?'Redução de momentum aplicada ao jogador que terminar em 3º lugar entre os destaques negativos da votação.':'Bônus de momentum aplicado ao jogador que terminar em 3º lugar na votação de Man of the Match.',
  '2º lugar':negative?'Redução de momentum aplicada ao jogador que terminar em 2º lugar entre os destaques negativos da votação.':'Bônus de momentum aplicado ao jogador que terminar em 2º lugar na votação de Man of the Match.',
  '1º lugar':negative?'Maior redução de momentum, aplicada ao jogador mais votado como Deception of the Match.':'Maior bônus de momentum, aplicado ao jogador mais votado como Man of the Match.',
 };
 const text=descriptions[label]||podiumDescriptions[label]||'Valor usado pelo Modo Carreira no cálculo de momentum.';
 const id=`help-career-${negative?'negative':'positive'}-${label.normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]+/gi,'-').toLowerCase()}`;
 return <label className="career-number"><span>{label}<HelpTip id={id} text={text}/></span><input type="number" value={value} min={min} max={max} step={step} onChange={event=>onChange(Number(event.target.value))}/></label>
}
function AuditPanel({data,loading,query,action,pageSize,onQuery,onAction,onPageSize,onPage}:any){
 const logs=data?.logs||[],actions=data?.actions||[],pagination=data?.pagination||{page:1,pageSize,total:0,totalPages:1},start=pagination.total?(pagination.page-1)*pagination.pageSize+1:0,end=Math.min(pagination.page*pagination.pageSize,pagination.total);
 return <section className="audit-panel" aria-busy={loading}><div className="audit-toolbar"><div><b>{pagination.total}</b><span>eventos encontrados</span></div><input placeholder="Buscar por usuário, ação ou registro…" value={query} onChange={event=>onQuery(event.target.value)}/><select value={action} onChange={event=>onAction(event.target.value)}><option value="ALL">Todas as ações</option>{actions.map((item:string)=><option key={item} value={item}>{actionLabel(item)}</option>)}</select><label className="audit-page-size"><span>Por página</span><select value={pageSize} onChange={event=>onPageSize(Number(event.target.value))}>{[10,25,50,100].map(size=><option key={size} value={size}>{size}</option>)}</select></label></div>{loading&&logs.length===0?<div className="admin-card audit-empty"><b>Carregando eventos…</b></div>:logs.length===0?<div className="admin-card audit-empty"><b>Nenhum evento encontrado</b><p>Revise os filtros ou aguarde novas atividades do sistema.</p></div>:<div className={loading?"audit-list loading":"audit-list"}>{logs.map((log:any)=><article key={log.id}><div className={`audit-icon action-${log.action.toLowerCase()}`}>{actionIcon(log.action)}</div><div className="audit-copy"><div><b>{actionLabel(log.action)}</b><span className="audit-entity">{entityLabel(log.entityType)}</span></div><p>{auditSubject(log)}</p><small>{log.administratorEmail} · {new Date(log.createdAt).toLocaleString('pt-BR')}</small>{(log.previousData||log.newData)&&<details><summary>Ver detalhes da alteração</summary><div className="audit-details">{log.previousData&&<div><b>Antes</b><pre>{JSON.stringify(log.previousData,null,2)}</pre></div>}{log.newData&&<div><b>Depois</b><pre>{JSON.stringify(log.newData,null,2)}</pre></div>}</div></details>}</div></article>)}</div>}<nav className="audit-pagination" aria-label="Paginação da auditoria"><button type="button" className="ghost" disabled={loading||pagination.page<=1} onClick={()=>onPage(pagination.page-1)}>← Anterior</button><span>Exibindo <b>{start}–{end}</b> de <b>{pagination.total}</b><small>Página {pagination.page} de {pagination.totalPages}</small></span><button type="button" className="ghost" disabled={loading||pagination.page>=pagination.totalPages} onClick={()=>onPage(pagination.page+1)}>Próxima →</button></nav></section>
}
function actionLabel(action:string){return({CREATE:'Cadastro',UPDATE:'Alteração',DELETE:'Exclusão',ACTIVATE:'Ativação',DEACTIVATE:'Desativação',LOGIN:'Login',LOGOUT:'Saída',CHANGE_PASSWORD:'Troca de senha',PASSWORD_RESET_REQUEST:'Solicitação de recuperação',PASSWORD_RESET:'Redefinição de senha',MEMBER_REGISTER:'Cadastro de jogador',MEMBER_LOGIN:'Login de jogador',MEMBER_LOGOUT:'Saída de jogador',MEMBER_ASSOCIATE:'Associação de jogador',MEMBER_DISASSOCIATE:'Desassociação de jogador',MEMBER_PROFILE_UPDATE:'Perfil atualizado pelo jogador',CAREER_MATCH_CONFIRMED:'Placar confirmado',CAREER_VOTE:'Voto registrado',CAREER_VOTING_CLOSED:'Votação encerrada'} as Record<string,string>)[action]||action}
function entityLabel(entity:string){return({player:'Jogador',member_account:'Conta de jogador',configuration:'Configurações',administrator:'Administrador',separation:'Separação',career_match:'Partida do Modo Carreira',career_vote:'Voto do Modo Carreira',career_configuration:'Modo Carreira'} as Record<string,string>)[entity]||entity}
function actionIcon(action:string){return({CREATE:'＋',UPDATE:'✎',DELETE:'×',ACTIVATE:'✓',DEACTIVATE:'−',LOGIN:'→',LOGOUT:'←',CHANGE_PASSWORD:'●',PASSWORD_RESET_REQUEST:'✉',PASSWORD_RESET:'◆'} as Record<string,string>)[action]||'•'}
function auditSubject(log:any){const data=log.newData||log.previousData||{};if(log.entityType==='player')return data.displayName||data.display_name||data.fullName||`Jogador ${log.entityId?.slice(0,8)||''}`;if(log.entityType==='administrator'||log.entityType==='member_account')return data.email||log.administratorEmail;if(log.entityType==='configuration')return 'Critérios de equilíbrio do sistema';if(log.entityType==='career_configuration')return 'Parâmetros de momentum e votação';if(log.entityType==='separation'||log.entityType==='career_match')return data.matchTitle||data.match_title||`Partida ${log.entityId?.slice(0,8)||''}`;if(log.entityType==='career_vote')return data.voterName||data.voter_player_id||`Voto ${log.entityId?.slice(0,8)||''}`;return log.entityId||'Registro do sistema'}
function Stat({label,value,note}:any){return <article className="stat"><small>{label}</small><b>{value}</b><span>{note}</span></article>}
function AdminAvatar({player}:{player:Player}){return <PlayerPhoto photoUrl={player.photoUrl} name={player.displayName} className="admin-photo"/>}
function PlayerTables({players,sort,onSort,onEdit}:{players:Player[];sort:PlayerSort;onSort:(key:PlayerSortKey)=>void;onEdit:(player:Player)=>void}){const goalkeepers=players.filter(player=>player.type==='goalkeeper'||player.primaryPosition==='Goleiro'),linePlayers=players.filter(player=>player.type!=='goalkeeper'&&player.primaryPosition!=='Goleiro');return <div className="player-list-stack"><section><div className="player-list-title"><div><h2>Jogadores de linha</h2><p>Velocidade, habilidade e marcação</p></div><b>{linePlayers.length}</b></div><div className="admin-card table player-table"><div className="tr player-tr line-player-tr th"><PlayerSortHeader label="Jogador" sortKey="name" sort={sort} onSort={onSort}/><PlayerSortHeader label="Tipo" sortKey="type" sort={sort} onSort={onSort}/><PlayerSortHeader label="Posição" sortKey="position" sort={sort} onSort={onSort}/><PlayerSortHeader label="Velocidade" sortKey="primaryRating" sort={sort} onSort={onSort}/><PlayerSortHeader label="Habilidade" sortKey="skill" sort={sort} onSort={onSort}/><PlayerSortHeader label="Marcação" sortKey="secondaryRating" sort={sort} onSort={onSort}/><PlayerSortHeader label="Momentum" sortKey="momentum" sort={sort} onSort={onSort}/><PlayerSortHeader label="Status" sortKey="active" sort={sort} onSort={onSort}/></div>{linePlayers.length?linePlayers.map(player=><button className="tr player-tr line-player-tr" key={player.id} onClick={()=>onEdit(player)}><PlayerIdentity player={player}/><span>{player.type==='guest'?'Convidado':'Mensalista'}</span><span>{player.primaryPosition}</span><span>{player.speed.toFixed(1)}</span><span>{player.skill.toFixed(1)}</span><span>{(player.marking??3).toFixed(1)}</span><PlayerMomentum player={player}/><PlayerStatus player={player}/></button>):<PlayerTableEmpty/>}</div></section><section><div className="player-list-title"><div><h2>Goleiros</h2><p>Posicionamento, habilidade e saída de gol</p></div><b>{goalkeepers.length}</b></div><div className="admin-card table player-table"><div className="tr player-tr goalkeeper-tr th"><PlayerSortHeader label="Goleiro" sortKey="name" sort={sort} onSort={onSort}/><PlayerSortHeader label="Posicionamento" sortKey="primaryRating" sort={sort} onSort={onSort}/><PlayerSortHeader label="Habilidade" sortKey="skill" sort={sort} onSort={onSort}/><PlayerSortHeader label="Saída de gol" sortKey="secondaryRating" sort={sort} onSort={onSort}/><PlayerSortHeader label="Momentum" sortKey="momentum" sort={sort} onSort={onSort}/><PlayerSortHeader label="Status" sortKey="active" sort={sort} onSort={onSort}/></div>{goalkeepers.length?goalkeepers.map(player=><button className="tr player-tr goalkeeper-tr" key={player.id} onClick={()=>onEdit(player)}><PlayerIdentity player={player}/><span>{(player.goalkeeperPositioning??player.speed).toFixed(1)}</span><span>{player.skill.toFixed(1)}</span><span>{(player.goalExit??player.marking??3).toFixed(1)}</span><PlayerMomentum player={player}/><PlayerStatus player={player}/></button>):<PlayerTableEmpty/>}</div></section></div>}
function PlayerIdentity({player}:{player:Player}){return <span className="person"><AdminAvatar player={player}/><b>{player.displayName}<small>{player.nickname}</small></b></span>}
function PlayerMomentum({player}:{player:Player}){return <span className={(player.momentum??0)>0?'momentum positive':(player.momentum??0)<0?'momentum negative':'momentum'}>{(player.momentum??0)>0?'+':''}{(player.momentum??0).toFixed(1)}</span>}
function PlayerStatus({player}:{player:Player}){return <span className={player.active?'status active':'status'}>{player.active?'Ativo':'Inativo'}</span>}
function PlayerTableEmpty(){return <div className="player-table-empty">Nenhum jogador encontrado nesta lista.</div>}
function PlayerSortHeader({label,sortKey,sort,onSort}:{label:string;sortKey:PlayerSortKey;sort:PlayerSort;onSort:(key:PlayerSortKey)=>void}){const fullLabel=({"Vel./Pos.":"Velocidade / Posicionamento","Hab.":"Habilidade","Mar./Saída":"Marcação / Saída de gol","Mom.":"Momentum"} as Record<string,string>)[label]||label,active=sort.key===sortKey,direction=active?sort.direction:null;return <button type="button" className={active?'sort-header active':'sort-header'} onClick={()=>onSort(sortKey)} aria-label={`Ordenar por ${fullLabel}${active?`, atualmente ${direction==='asc'?'crescente':'decrescente'}`:''}`} title={`Ordenar por ${fullLabel}`}><span>{fullLabel}</span><i aria-hidden="true">{direction==='asc'?'↑':direction==='desc'?'↓':'↕'}</i></button>}
function comparePlayers(a:Player,b:Player,sort:PlayerSort){const aValue=playerSortValue(a,sort.key),bValue=playerSortValue(b,sort.key);let result=typeof aValue==='number'&&typeof bValue==='number'?aValue-bValue:String(aValue).localeCompare(String(bValue),'pt-BR',{sensitivity:'base',numeric:true});if(result===0)result=a.displayName.localeCompare(b.displayName,'pt-BR',{sensitivity:'base',numeric:true});return sort.direction==='asc'?result:-result}
function playerSortValue(player:Player,key:PlayerSortKey){const goalkeeper=player.type==='goalkeeper'||player.primaryPosition==='Goleiro';switch(key){case'name':return player.displayName;case'type':return player.type==='guest'?'Convidado':goalkeeper?'Goleiro':'Mensalista';case'position':return player.primaryPosition;case'primaryRating':return goalkeeper?(player.goalkeeperPositioning??player.speed):player.speed;case'skill':return player.skill;case'secondaryRating':return goalkeeper?(player.goalExit??player.marking??3):(player.marking??3);case'momentum':return player.momentum??0;case'active':return player.active?1:0}}
function RatingSlider({label,value,onChange}:{label:string,value:number,onChange:(value:number)=>void}){return <label className="rating-slider"><span>{label}</span><input type="range" min="1" max="5" step="0.1" value={value} onChange={event=>onChange(Math.round(Number(event.target.value)*10)/10)}/><output>{Number(value).toFixed(1)}</output><small><span>1</span><span>5</span></small></label>}
